1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	};
15	
16	export function quote(items: { type: string }[], context: QuoteContext): number {
17	  const itemsBasePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
18	  return itemsBasePremium + POLICY_FEE;
19	}
20	
21	export function claim(): unknown {
22	  return undefined;
23	}
